def rollback(self, count: int = 1) -> int:
    rolled_back = 0
    for _ in range(count):
        if not self.applied:
            break
        name = self.applied.pop()
        module = self._load_module(name)
        if hasattr(module, 'down'):
            module.down(self.db)
        else:
            raise RuntimeError(f'Migration {name} has no down() function')
        rolled_back += 1
    return rolled_back
